import{_ as e,a as i,b as t}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as o,o as d,c as r,a2 as n}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Dodawanie kanału Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/cloudflare-r2.md","filePath":"pl-PL/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),l={name:"pl-PL/upload/cloudflare-r2.md"};function c(u,a,p,z,s,y){return d(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="dodawanie-kanału-cloudflare-r2" tabindex="-1">Dodawanie kanału Cloudflare R2 <a class="header-anchor" href="#dodawanie-kanału-cloudflare-r2" aria-label="Permalink to &quot;Dodawanie kanału Cloudflare R2&quot;">​</a></h1><h2 id="kiedy-warto-go-uzyc" tabindex="-1">Kiedy warto go użyć <a class="header-anchor" href="#kiedy-warto-go-uzyc" aria-label="Permalink to &quot;Kiedy warto go użyć&quot;">​</a></h2><p>Użyj Cloudflare R2, gdy:</p><ul><li>Twoja strona ImgBed działa już w Cloudflare i chcesz przechowywać pliki w buckecie R2 na tym samym koncie Cloudflare.</li><li>Nie chcesz konfigurować osobnego endpointu S3, access key i secret key.</li><li>Odczyt i zapis mają przechodzić przez binding R2 w Worker lub Pages przy minimalnej konfiguracji.</li></ul><p>W skrócie:</p><p>Kanału R2 nie tworzy się ręcznie w panelu administracyjnym ImgBed. Najpierw trzeba powiązać bucket R2 z projektem Cloudflare, a nazwa zmiennej bindingu musi brzmieć dokładnie <code>img_r2</code>.</p><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><ul><li>Konto Cloudflare.</li><li>Istniejący bucket R2.</li><li>Uprawnienia do zarządzania projektem Cloudflare, na którym wdrożony jest ImgBed.</li></ul><h2 id="konfiguracja-w-cloudflare" tabindex="-1">Konfiguracja w Cloudflare <a class="header-anchor" href="#konfiguracja-w-cloudflare" aria-label="Permalink to &quot;Konfiguracja w Cloudflare&quot;">​</a></h2><h3 id="_1-utworz-bucket-r2" tabindex="-1">1. Utwórz bucket R2 <a class="header-anchor" href="#_1-utworz-bucket-r2" aria-label="Permalink to &quot;1. Utwórz bucket R2&quot;">​</a></h3><ol><li>Zaloguj się do Cloudflare Dashboard.</li><li>Otwórz <code>R2 Object Storage</code>.</li><li>Kliknij Create bucket.</li><li>Wybierz nazwę bucketu, na przykład <code>imgbed</code>.</li></ol><p>W tym buckecie będą przechowywane przesłane pliki.</p><p><img src="'+e+'" alt="Utwórz bucket R2" loading="lazy"></p><h3 id="_2-powiaz-bucket-z-projektem-imgbed" tabindex="-1">2. Powiąż bucket z projektem ImgBed <a class="header-anchor" href="#_2-powiaz-bucket-z-projektem-imgbed" aria-label="Permalink to &quot;2. Powiąż bucket z projektem ImgBed&quot;">​</a></h3><p>Wybierz miejsce bindingu zgodnie z typem wdrożenia:</p><table tabindex="0"><thead><tr><th>Typ wdrożenia</th><th>Miejsce bindingu</th></tr></thead><tbody><tr><td>Pages</td><td>Bieżący projekt Pages -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Bieżący Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Podczas dodawania bindingu kluczowe są te pola:</p><table tabindex="0"><thead><tr><th>Pole</th><th>Wartość</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Wybierz utworzony bucket</td></tr></tbody></table><p>Nazwa zmiennej musi być dokładnie <code>img_r2</code>. Przesyłanie, odczyt i usuwanie plików R2 zależą od tej nazwy bindingu.</p><h3 id="_3-wdroz-projekt-ponownie" tabindex="-1">3. Wdróż projekt ponownie <a class="header-anchor" href="#_3-wdroz-projekt-ponownie" aria-label="Permalink to &quot;3. Wdróż projekt ponownie&quot;">​</a></h3><p>Po zapisaniu bindingu wdróż ImgBed ponownie, aby runtime Worker lub Pages mógł uzyskać dostęp do <code>img_r2</code>.</p><h2 id="co-zobaczysz-w-imgbed" tabindex="-1">Co zobaczysz w ImgBed <a class="header-anchor" href="#co-zobaczysz-w-imgbed" aria-label="Permalink to &quot;Co zobaczysz w ImgBed&quot;">​</a></h2><p>Gdy binding R2 będzie dostępny, otwórz:</p><ol><li>Ustawienia systemowe.</li><li>Ustawienia przesyłania.</li><li>Kanał <code>Cloudflare R2</code>.</li></ol><p>System automatycznie tworzy jeden stały kanał:</p><table tabindex="0"><thead><tr><th>Pole</th><th>Stała wartość</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td><code>Cloudflare R2</code></td></tr><tr><td>Typ kanału</td><td><code>cfr2</code></td></tr><tr><td>Tryb pamięci</td><td><code>binding</code></td></tr><tr><td>Źródło konfiguracji</td><td>Binding środowiskowy</td></tr></tbody></table><p>To stały kanał bindingu. Nie trzeba klikać Dodaj kanał, aby go utworzyć, i nie da się go usunąć jak zwykłego kanału.</p><h2 id="pola-edytowalne-w-panelu-administracyjnym" tabindex="-1">Pola edytowalne w panelu administracyjnym <a class="header-anchor" href="#pola-edytowalne-w-panelu-administracyjnym" aria-label="Permalink to &quot;Pola edytowalne w panelu administracyjnym&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Działanie</th><th>Wymagane</th></tr></thead><tbody><tr><td>Włącz kanał</td><td>Określa, czy R2 bierze udział w wyborze kanału przesyłania.</td><td>Tak</td></tr><tr><td>Account ID</td><td>Potrzebne tylko przy włączonych limitach pojemności, gdy trzeba odpytywać oficjalne użycie R2.</td><td>Zalecane przy limitach</td></tr><tr><td>Nazwa bucketu</td><td>Potrzebna tylko przy włączonych limitach pojemności, gdy trzeba odpytywać oficjalne użycie R2.</td><td>Zalecane przy limitach</td></tr><tr><td>Limit pojemności</td><td>Określa, czy ten kanał R2 jest wybierany na podstawie dostępnej pojemności.</td><td>Nie</td></tr><tr><td>Próg</td><td>Zatrzymuje zapis do tego kanału po osiągnięciu podanego procentu użycia.</td><td>Wymagane przy limitach</td></tr></tbody></table><p>Account ID możesz skopiować z panelu informacji o koncie w Cloudflare Dashboard. Wypełnij je tylko wtedy, gdy chcesz, aby ImgBed odpytywał i egzekwował użycie limitu R2.</p><p><img src="'+i+'" alt="Pobierz Account ID" loading="lazy"></p><h2 id="kroki-konfiguracji" tabindex="-1">Kroki konfiguracji <a class="header-anchor" href="#kroki-konfiguracji" aria-label="Permalink to &quot;Kroki konfiguracji&quot;">​</a></h2><ol><li>Utwórz bucket R2 w Cloudflare.</li><li>Otwórz ustawienia Cloudflare projektu ImgBed.</li><li>Dodaj binding bucketu R2.</li><li>Ustaw <code>Variable name</code> na <code>img_r2</code>.</li><li>Wybierz utworzony bucket R2.</li><li>Zapisz binding i wdróż ImgBed ponownie.</li><li>Wróć do ImgBed -&gt; Ustawienia systemowe -&gt; Ustawienia przesyłania.</li><li>Sprawdź, czy kanał <code>Cloudflare R2</code> jest widoczny i włączony.</li></ol><p>Jeśli R2 ma być wybierany na podstawie pojemności, włącz limit pojemności, a potem wpisz Account ID, nazwę bucketu, limit i próg przed zapisaniem.</p><p><img src="'+t+'" alt="Konfiguracja limitów pojemności" loading="lazy"></p><h2 id="jak-sprawdzic" tabindex="-1">Jak sprawdzić <a class="header-anchor" href="#jak-sprawdzic" aria-label="Permalink to &quot;Jak sprawdzić&quot;">​</a></h2><ul><li>Stały kanał <code>Cloudflare R2</code> pojawia się w Ustawieniach przesyłania.</li><li>Karta kanału pokazuje, że kanał jest włączony.</li><li>Mały plik testowy przesyła się poprawnie, a zwrócony link otwiera się normalnie.</li><li>Jeśli przy otwieraniu pliku pojawia się <code>R2 database binding is not configured</code>, runtime nie otrzymał bindingu <code>img_r2</code>. Sprawdź nazwę bindingu w Cloudflare i wdróż projekt ponownie.</li></ul>',37)])])}const m=o(l,[["render",c]]);export{k as __pageData,m as default};
